scwin.f_MasterDetail = function (){
    /*
    var condition = "?";
    var row = ds_MasterSearchList.RowPosition;
    var strExpertDetailUrl = "/il/airout/aobl/ar_103_01_01b.jsp";
    var strImportDetailUrl = "/il/airinb/aibl/ar_202_01_01b.jsp";


    if(row > 0){
        //선택된 오더 정보 : 오더번호 / 화물구분
